    if (!isVariantFootless) {
        const { footerOuterDiv } = await getModalFooterInternals(modalFooterElem);
        const heightFtr = await footerOuterDiv.getSize('height');
        if (heightFtr > 0) {
            totalModalElemHeight += heightFtr;
        }
    }
    const percentPageHeightUtilized = totalModalElemHeight / windowHeight;
    if (!isVariantFootless) {
        const { footerOuterDiv } = await getModalFooterInternals(modalFooterElem);
        const heightFtr = await footerOuterDiv.getSize('height');
        if (heightFtr > 0) {
            totalModalElemHeight += heightFtr;
        }
    }
    if (modalSize === MODAL_SIZE_FULL &&
        windowWidth <= MODAL_FULL_SCREEN_SMALL_BREAKPOINT) {
        expect(percentPageHeightUtilized).toBeGreaterThan(MODAL_FULL_SCREEN_USE_PERCENT);
        expect(modalBodyStyleProps[MAX_HEIGHT]).toBeUndefined();
        expect(modalBodyStyleProps[MIN_HEIGHT]).toBeUndefined();
    }
    else {
        expect(percentPageHeightUtilized).toBeLessThan(MODAL_DEFAULT_SCREEN_USE_PERCENT);
        expect(modalBodyStyleProps[MAX_HEIGHT]).toBeDefined();
        expect(modalBodyStyleProps[MIN_HEIGHT]).toBeDefined();
        expect(modalBodyStyleProps[MAX_HEIGHT]).not.toEqual(modalBodyStyleProps[MIN_HEIGHT]);
        expect(modalBodyStyleProps[MIN_HEIGHT]).toEqual(MODAL_BODY_MIN_HEIGHT_PX);
    }
